import docx
d = docx.Document('documents/draft-settlement-agreement.docx')
print('Total paragraphs:', len(d.paragraphs))
print('Total tables:', len(d.tables))
# Show paragraph index, style, text preview, and number of runs
for i, p in enumerate(d.paragraphs):
    style = p.style.name if p.style else 'None'
    txt = p.text[:70].replace(chr(10),' ')
    nruns = len(p.runs)
    # detect bold/underline in runs
    fmt = []
    for r in p.runs:
        if r.bold: fmt.append('B')
        if r.underline: fmt.append('U')
        if r.italic: fmt.append('I')
    fmtstr = ','.join(sorted(set(fmt))) if fmt else '-'
    print(f'{i:3d} | {style:20s} | runs={nruns:2d} | {fmtstr:6s} | {txt}')
" 2>&1 | head -120"}

