from lxml import etree
W='http://schemas.openxmlformats.org/wordprocessingml/2006/main'
tree=etree.parse('workdir_redline/word/document.xml')
root=tree.getroot(); body=root.find(f'{{{W}}}body'); paras=body.findall(f'{{{W}}}p')
def pt(p):
    out=[]
    for el in p.iter():
        tag=el.tag.split('}')[-1]
        if tag=='t':
            anc=el.getparent(); ctx=''
            while anc is not None and anc.tag!=f'{{{W}}}p':
                at=anc.tag.split('}')[-1]
                if at in ('ins','del'): ctx=at.upper(); break
                anc=anc.getparent()
            out.append(('['+ctx+']' if ctx else '')+(el.text or ''))
        elif tag=='delText':
            out.append('[DEL]'+(el.text or ''))
    return ''.join(out)
for i in [78,88,98]:
    print(f'===== P{i} =====')
    print(pt(paras[i]))
    print()
""}

